const SPRITES={
  idle:{src:"data:image/png;base64,",frames:18},
  run:{src:"data:image/png;base64,",frames:12},
  throw:{src:"data:image/png;base64,",frames:12}
};
const FRAME_W=160, FRAME_H=170;
const DEFAULT_CONFIG={
  characterScale:0.6, playerSpeed:245, idleFps:9, runFps:14, throwFps:18,
  colors:['#4ac6db','#d46f72','#77b45c','#917bd0'],
  matchTime:90, mummyCount:12, mummyScale:1.2, mummySpeed:92, passRange:450, startingLives:3
};
let CONFIG=structuredClone(DEFAULT_CONFIG);
const canvas=document.getElementById('game'),ctx=canvas.getContext('2d'),W=canvas.width,H=canvas.height,WORLD=3100;
const keys=new Set(),players=[],enemies=[],traps=[],particles=[]; const images={};
let started=false,last=performance.now(),camera=0,cameraY=0,remaining=CONFIG.matchTime,score=0,lives=CONFIG.startingLives,holder=0,passAnim=null,invuln=0;
const $=id=>document.getElementById(id), clamp=(v,a,b)=>Math.max(a,Math.min(b,v)), dist=(a,b)=>Math.hypot(a.x-b.x,a.y-b.y), rand=(a,b)=>a+Math.random()*(b-a);
function loadImages(){return Promise.all(Object.entries(SPRITES).map(([k,v])=>new Promise((res,rej)=>{const img=new Image();img.onload=()=>{images[k]=img;res()};img.onerror=rej;img.src=v.src})))}
function filters(){return ['hue-rotate(165deg) saturate(1.28)','hue-rotate(330deg) saturate(1.28)','hue-rotate(70deg) saturate(1.25)','hue-rotate(250deg) saturate(1.25)']}
function syncFormFromConfig(){for(const k of ['characterScale','playerSpeed','idleFps','runFps','throwFps','matchTime','mummyCount','mummyScale','mummySpeed','passRange','startingLives'])$(k).value=CONFIG[k];CONFIG.colors.forEach((c,i)=>$('color'+i).value=c)}
function readForm(){const next=structuredClone(CONFIG);for(const k of ['characterScale','playerSpeed','idleFps','runFps','throwFps','matchTime','mummyCount','mummyScale','mummySpeed','passRange','startingLives'])next[k]=Number($(k).value);next.colors=[0,1,2,3].map(i=>$('color'+i).value);return next}
function resetGame(){players.length=enemies.length=traps.length=particles.length=0;[[150,340],[315,235],[410,420],[565,315]].forEach((p,i)=>players.push({x:p[0],y:p[1],vx:0,vy:0,slot:i,phase:i*1.4,throwTimer:0,facing:1}));for(let i=0;i<CONFIG.mummyCount;i++){const e={x:760+i*((WORLD-900)/Math.max(1,CONFIG.mummyCount-1))+rand(-40,40),y:rand(190,500),baseY:0,phase:rand(0,6),stun:0};e.baseY=e.y;enemies.push(e)}[[980,360,62],[1450,235,70],[1940,420,68],[2400,295,74],[2740,410,65]].forEach(v=>traps.push({x:v[0],y:v[1],r:v[2]}));camera=0;cameraY=0;remaining=CONFIG.matchTime;score=0;lives=CONFIG.startingLives;holder=0;passAnim=null;invuln=0;updateHud()}
function updateHud(){$('time').textContent=Math.ceil(Math.max(0,remaining));$('score').textContent=Math.floor(score);$('lives').textContent=lives}
function start(){resetGame();started=true;$('overlay').classList.add('hidden');last=performance.now()}
function finish(win){started=false;$('overlay').classList.remove('hidden');const card=$('overlay').querySelector('.card');card.querySelector('.eyebrow').textContent=win?'TEMPLE UNLOCKED':'MISSION FAILED';card.querySelector('h1').innerHTML=win?'CHIẾN<br>THẮNG':'HẾT<br>LƯỢT';card.querySelector('p').innerHTML=win?`Điểm số: <b>${Math.floor(score)}</b>.`:`Điểm số: <b>${Math.floor(score)}</b>. Hãy chỉnh gameplay rồi thử lại.`;$('startBtn').textContent='CHƠI LẠI'}
function pass(){if(!started||passAnim)return;const from=players[holder];let best=-1,bestVal=-1e9;players.forEach((p,i)=>{if(i===holder)return;const d=dist(from,p),dx=p.x-from.x;if(d<=CONFIG.passRange){const v=dx*1.4-d*.25;if(v>bestVal){bestVal=v;best=i}}});if(best<0)return;passAnim={from:holder,to:best,t:0,duration:.42,startX:from.x,startY:from.y-70};players[holder].throwTimer=.42;score+=40}
function loseLife(){if(invuln>0)return;lives--;invuln=1.7;score=Math.max(0,score-100);const p=players[holder];p.x=Math.max(100,p.x-140);p.y=330;p.vx=-150;p.vy=0;for(let i=0;i<16;i++)particles.push({x:p.x,y:p.y,vx:rand(-150,150),vy:rand(-170,50),life:rand(.3,.8),color:'#e36a63'});if(lives<=0)finish(false)}
function update(dt){if(!started)return;remaining-=dt;invuln=Math.max(0,invuln-dt);if(remaining<=0){remaining=0;finish(false);updateHud();return}const p=players[0];let dx=0,dy=0;if(keys.has('KeyD')||keys.has('ArrowRight'))dx++;if(keys.has('KeyA')||keys.has('ArrowLeft'))dx--;if(keys.has('KeyS')||keys.has('ArrowDown'))dy++;if(keys.has('KeyW')||keys.has('ArrowUp'))dy--;const m=Math.hypot(dx,dy)||1;dx/=m;dy/=m;p.vx+=(dx*CONFIG.playerSpeed-p.vx)*Math.min(1,dt*8);p.vy+=(dy*CONFIG.playerSpeed-p.vy)*Math.min(1,dt*8);p.x+=p.vx*dt;p.y+=p.vy*dt;if(Math.abs(p.vx)>5)p.facing=Math.sign(p.vx);p.x=clamp(p.x,50,WORLD-80);p.y=clamp(p.y,135,565);for(let i=1;i<players.length;i++){const q=players[i];q.phase+=dt*(1.5+i*.15);q.throwTimer=Math.max(0,q.throwTimer-dt);const tx=p.x+145+i*105,ty=235+((i*107)%245)+Math.sin(q.phase)*45;q.vx+=(clamp(tx-q.x,-1,1)*150-q.vx)*Math.min(1,dt*3.8);q.vy+=(clamp(ty-q.y,-1,1)*125-q.vy)*Math.min(1,dt*3.8);q.x+=q.vx*dt;q.y+=q.vy*dt;if(Math.abs(q.vx)>5)q.facing=Math.sign(q.vx);q.x=clamp(q.x,p.x-180,p.x+620);q.y=clamp(q.y,135,565)}players[0].throwTimer=Math.max(0,players[0].throwTimer-dt);if(passAnim){passAnim.t+=dt/passAnim.duration;if(passAnim.t>=1){holder=passAnim.to;passAnim=null;score+=70}}const c=players[holder];traps.forEach(t=>{if(Math.hypot(c.x-t.x,c.y-t.y)<t.r){c.vx*=Math.pow(.025,dt);c.vy*=Math.pow(.025,dt)}});enemies.forEach(e=>{e.phase+=dt;e.stun=Math.max(0,e.stun-dt);const d=dist(e,c);if(e.stun<=0&&d<390){e.x+=(c.x-e.x)/(d||1)*CONFIG.mummySpeed*dt;e.y+=(c.y-e.y)/(d||1)*CONFIG.mummySpeed*dt}else e.y+=(e.baseY+Math.sin(e.phase)*38-e.y)*dt*.75;if(!passAnim&&d<34*CONFIG.mummyScale+18){loseLife();e.stun=.8}});for(let i=particles.length-1;i>=0;i--){const v=particles[i];v.life-=dt;v.x+=v.vx*dt;v.y+=v.vy*dt;v.vy+=180*dt;if(v.life<=0)particles.splice(i,1)}camera+=(clamp(c.x-W*.34,0,WORLD-W)-camera)*(1-Math.pow(.001,dt));const targetCameraY=clamp(c.y-H*.56,-55,75);cameraY+=(targetCameraY-cameraY)*(1-Math.pow(.008,dt));score+=Math.max(0,p.vx)*dt*.015;if(c.x>WORLD-145){score+=remaining*15;finish(true)}updateHud()}
function drawBg(){
const sky=ctx.createLinearGradient(0,0,0,H);
sky.addColorStop(0,'#12253c');sky.addColorStop(.47,'#bc6647');sky.addColorStop(.68,'#dfaa57');sky.addColorStop(1,'#bd7933');
ctx.fillStyle=sky;ctx.fillRect(0,0,W,H);
const sx=855-camera*.04,sy=105-cameraY*.08,g=ctx.createRadialGradient(sx,sy,5,sx,sy,95);
g.addColorStop(0,'#fff6c5');g.addColorStop(.28,'rgba(234,184,70,.9)');g.addColorStop(1,'rgba(234,184,70,0)');
ctx.fillStyle=g;ctx.beginPath();ctx.arc(sx,sy,95,0,Math.PI*2);ctx.fill();
ctx.fillStyle='#8b5535';
for(let i=0;i<8;i++){
 const x=i*440-camera*.22-100,s=75+(i%3)*18,y=195-cameraY*.22;
 ctx.beginPath();ctx.moveTo(x-s,y);ctx.lineTo(x,y-s);ctx.lineTo(x+s,y);ctx.closePath();ctx.fill()
}
const groundTop=120-cameraY*.32;
const ground=ctx.createLinearGradient(0,groundTop,0,H+80);
ground.addColorStop(0,'#d8a554');ground.addColorStop(1,'#ad672d');
ctx.fillStyle=ground;ctx.fillRect(0,groundTop,W,H-groundTop+90);
const tx=WORLD-110-camera,ty=-cameraY;
if(tx>-180&&tx<W+180){
 ctx.fillStyle='#56382c';ctx.fillRect(tx-84,175+ty,168,355);
 ctx.fillStyle='#93633f';ctx.fillRect(tx-68,190+ty,136,340);
 ctx.fillStyle='#1c1a1a';ctx.fillRect(tx-30,332+ty,60,198);
 ctx.fillStyle='#d2a84e';ctx.beginPath();ctx.arc(tx,288+ty,16,0,Math.PI*2);ctx.fill()
}}
function shadow(x,y,w,h,a=.24){ctx.fillStyle=`rgba(38,24,18,${a})`;ctx.beginPath();ctx.ellipse(x-camera,y+18-cameraY,w,h,0,0,Math.PI*2);ctx.fill()}
function drawTrap(t){const x=t.x-camera,y=t.y-cameraY;if(x<-100||x>W+100)return;const g=ctx.createRadialGradient(x,y,4,x,y,t.r);g.addColorStop(0,'rgba(55,34,23,.65)');g.addColorStop(.72,'rgba(90,54,30,.35)');g.addColorStop(1,'rgba(90,54,30,0)');ctx.fillStyle=g;ctx.beginPath();ctx.arc(x,y,t.r,0,Math.PI*2);ctx.fill()}
function drawPlayer(p,i,now){const x=p.x-camera,y=p.y-cameraY;if(x<-130||x>W+130)return;shadow(p.x,p.y,25*CONFIG.characterScale,7*CONFIG.characterScale);const moving=Math.hypot(p.vx,p.vy)>20,set=p.throwTimer>0?'throw':moving?'run':'idle',sp=SPRITES[set],fps=CONFIG[set==='idle'?'idleFps':set==='run'?'runFps':'throwFps'],fi=Math.floor(now/1000*fps)%sp.frames,sx=fi*FRAME_W,scale=CONFIG.characterScale,dw=140*scale,dh=149*scale;ctx.save();ctx.translate(x,y);if(p.facing<0)ctx.scale(-1,1);ctx.filter=filters()[i];if(invuln>0&&i===holder&&Math.floor(invuln*10)%2===0)ctx.globalAlpha=.3;ctx.drawImage(images[set],sx,0,FRAME_W,FRAME_H,-dw/2,-dh+32*scale,dw,dh);ctx.restore();ctx.filter='none';ctx.globalAlpha=1;ctx.font='900 11px system-ui';ctx.textAlign='center';ctx.fillStyle=CONFIG.colors[i];ctx.fillText('P'+(i+1),x,y-dh+20);if(i===holder){ctx.strokeStyle='#fff0a5';ctx.lineWidth=3;ctx.beginPath();ctx.arc(x,y-8,31*scale,0,Math.PI*2);ctx.stroke()}}
function drawMummy(e){const x=e.x-camera,y=e.y-cameraY,s=CONFIG.mummyScale;if(x<-120||x>W+120)return;shadow(e.x,e.y,34*s,10*s,.28);ctx.save();ctx.translate(x,y);ctx.scale(s,s);ctx.fillStyle='#cfc3a7';ctx.beginPath();ctx.roundRect(-18,-28,36,52,9);ctx.fill();ctx.strokeStyle='#8e846f';ctx.lineWidth=3;for(let yy=-18;yy<20;yy+=8){ctx.beginPath();ctx.moveTo(-15,yy);ctx.lineTo(15,yy+4);ctx.stroke()}ctx.fillStyle='#b84038';ctx.fillRect(-9,-16,6,4);ctx.fillRect(4,-16,6,4);ctx.strokeStyle='#cfc3a7';ctx.lineWidth=7;ctx.lineCap='round';ctx.beginPath();ctx.moveTo(-14,-4);ctx.lineTo(-29,-12);ctx.stroke();ctx.beginPath();ctx.moveTo(14,-4);ctx.lineTo(30,-10);ctx.stroke();ctx.restore()}
function ballPos(){if(passAnim){const t=Math.min(1,passAnim.t),to=players[passAnim.to];return{x:passAnim.startX+(to.x-passAnim.startX)*t,y:passAnim.startY+(to.y-70-passAnim.startY)*t-Math.sin(Math.PI*t)*80}}const p=players[holder];return{x:p.x+18,y:p.y-75*CONFIG.characterScale}}
function drawBall(){const b=ballPos(),x=b.x-camera,y=b.y-cameraY,g=ctx.createRadialGradient(x,y,2,x,y,32);g.addColorStop(0,'#fff9c6');g.addColorStop(.35,'#e1b348');g.addColorStop(1,'rgba(225,179,72,0)');ctx.fillStyle=g;ctx.beginPath();ctx.arc(x,y,32,0,Math.PI*2);ctx.fill();ctx.fillStyle='#dfb44f';ctx.beginPath();ctx.arc(x,y,9,0,Math.PI*2);ctx.fill()}
function draw(now){drawBg();traps.forEach(drawTrap);[...enemies.map(e=>({y:e.y,t:'e',o:e})),...players.map((p,i)=>({y:p.y,t:'p',o:p,i}))].sort((a,b)=>a.y-b.y).forEach(v=>v.t==='e'?drawMummy(v.o):drawPlayer(v.o,v.i,now));drawBall();particles.forEach(v=>{ctx.globalAlpha=Math.max(0,v.life);ctx.fillStyle=v.color;ctx.fillRect(v.x-camera,v.y-cameraY,5,5)});ctx.globalAlpha=1;ctx.fillStyle='rgba(9,14,20,.55)';ctx.fillRect(18,H-27,W-36,6);ctx.fillStyle='#d2a84e';ctx.fillRect(18,H-27,(players[holder].x/WORLD)*(W-36),6)}
function frame(now){const dt=Math.min(.033,(now-last)/1000||0);last=now;update(dt);draw(now);requestAnimationFrame(frame)}
const stageElement=document.querySelector('.stage');
function toggleFullscreen(){
  if(!document.fullscreenElement){
    stageElement.requestFullscreen?.().catch(()=>{});
  }else{
    document.exitFullscreen?.();
  }
}
function startFullscreen(){
  if(!document.fullscreenElement){
    stageElement.requestFullscreen?.().catch(()=>{});
  }
  start();
}
addEventListener('keydown',e=>{
  keys.add(e.code);
  if(['ArrowUp','ArrowDown','ArrowLeft','ArrowRight','Space'].includes(e.code))e.preventDefault();
  if(e.code==='Space'&&!e.repeat)pass();
  if(e.code==='KeyR')start();
  if(e.code==='KeyF'&&!e.repeat)toggleFullscreen();
});
addEventListener('keyup',e=>keys.delete(e.code));
$('startBtn').onclick=startFullscreen;
$('fullscreenBtn').onclick=toggleFullscreen;
document.addEventListener('fullscreenchange',()=>{
  $('fullscreenBtn').textContent=document.fullscreenElement?'EXIT FULLSCREEN':'FULLSCREEN';
});
loadImages().then(()=>{
  resetGame();
  requestAnimationFrame(frame);
}).catch(err=>{
  console.error(err);
  alert('Không tải được sprite nhúng.');
});
